"""
Manages game logic and rules enforcement.
"""

from board import Board
from piece import Piece
import re

class GameManager:
    def __init__(self):
        self.board = Board()
        self.current_player = 'W'

    def start_game(self):
        while True:
            print("Current Board:")
            self.board.print_board()
            move = input(f"Player {self.current_player}, enter your move (e.g., A1-B2): ")
            if move.lower() == 'q':
                print("Game over!")
                break
            try:
                from_pos, to_pos = self.parse_move(move)
                self.make_move(from_pos, to_pos)
                if self.check_winner():
                    print(f"Player {self.current_player} wins!")
                    break
                self.switch_player()
            except ValueError as e:
                print(e)

    def parse_move(self, move):
        # Parse the move input
        match = re.match(r'([a-h])([1-8])-([a-h])([1-8])', move)
        if not match:
            raise ValueError("Invalid move format. Use A1-B2 notation.")
        from_col, from_row, to_col, to_row = match.groups()
        return (int(from_row) - 1, ord(from_col) - ord('A')), (int(to_row) - 1, ord(to_col) - ord('A'))

    def make_move(self, from_pos, to_pos):
        # Make a move on the board
        piece = self.board.get_piece(from_pos)
        if piece and piece.color == self.current_player:
            self.board.move_piece(from_pos, to_pos)
            if self.check_capture(to_pos):
                self.make_capture(to_pos)

    def check_winner(self):
        # Check for game winner
        pieces = [self.board.get_piece((i, j)) for i in range(8) for j in range(8)]
        if not any(p and p.color == 'W' for p in pieces):
            return True
        if not any(p and p.color == 'B' for p in pieces):
            return True
        return False

    def switch_player(self):
        # Switch current player
        self.current_player = 'W' if self.current_player == 'B' else 'B'

    def check_capture(self, to_pos):
        # Check for capture and make it
        x, y = to_pos
        directions = [(-1, 1), (-1, -1), (1, 1), (1, -1)]
        for dx, dy in directions:
            if 0 <= x + dx < 8 and 0 <= y + dy < 8 and self.board.get_piece((x + dx, y + dy)):
                return True
        return False

