def initialize_board():
    board = [
        ['b' if (i+j) % 2 == 1 else '.' for j in range(8)] for i in range(8)
    ]
    for i in range(3):
        for j in range(8):
            if (i + j) % 2 == 1:
                board[i][j] = 'B'
    for i in range(5, 8):
        for j in range(8):
            if (i + j) % 2 == 1:
                board[i][j] = 'r'
    return board

def display_board(board):
    for row in board:
        print(' '.join(row))
    print()

def is_valid_move(board, start_pos, end_pos, turn):
    # Basic move validation
    x_start, y_start = start_pos
    x_end, y_end = end_pos

    if (abs(x_end - x_start) != 1 and abs(x_end - x_start) != 2) or \
       abs(y_end - y_start) != 1:
        return False

    if turn == 'r' and board[x_start][y_start] in ['R', '.']:
        return False
    if turn == 'b' and board[x_start][y_start] in ['B', '.']:
        return False

    if abs(x_end - x_start) == 2:
        if (turn == 'r' and board[(x_start + x_end) // 2][(y_start + y_end) // 2] != 'b') or \
           (turn == 'b' and board[(x_start + x_end) // 2][(y_start + y_end) // 2] != 'R'):
            return False

    if turn == 'r' and board[x_end][y_end] != '.':
        return False
    if turn == 'b' and board[x_end][y_end] != '.':
        return False

    return True

def make_move(board, start_pos, end_pos):
    x_start, y_start = start_pos
    x_end, y_end = end_pos
    piece = board[x_start][y_start]

    board[x_start][y_start] = '.'
    board[x_end][y_end] = piece

    # Handle capture
    if abs(x_end - x_start) == 2:
        if (turn == 'r' and board[(x_start + x_end) // 2][(y_start + y_end) // 2] != 'b') or \
           (turn == 'b' and board[(x_start + x_end) // 2][(y_start + y_end) // 2] != 'R'):
            board[(x_start + x_end) // 2][(y_start + y_end) // 2] = '.'

    # Handle kinging
    if turn == 'r' and end_pos[0] == 0:
        board[end_pos[0]][end_pos[1]] = 'R'
    if turn == 'b' and end_pos[0] == 7:
        board[end_pos[0]][end_pos[1]] = 'B'

    return board

